local M = {}

-- TODO switch to using 8-bit color (256 colors)
-- https://en.wikipedia.org/wiki/ANSI_escape_code#8-bit

local color_keys = {

    -- foreground colors
    black             = 30,
    red               = 31,
    green             = 32,
    yellow            = 33,
    blue              = 34,
    magenta           = 35,
    cyan              = 36,
    white             = 37,

    -- background colors
    black_bg          = 40,
    red_bg            = 41,
    green_bg          = 42,
    yellow_bg         = 43,
    blue_bg           = 44,
    magenta_bg        = 45,
